  7→import { isGeminiEnterpriseEnvironment } from '@/core/utils/gemini';
  8→import { startFormulaCopy } from '@/features/formulaCopy';
  9→import { initI18n } from '@/utils/i18n';
 10→
 11→import { startChangelog } from './changelog/index';
 12→import { startChatWidthAdjuster } from './chatWidth/index';
 13→import { startContextSync } from './contextSync';
 14→import { startDeepResearchExport } from './deepResearch/index';
 15→import DefaultModelManager from './defaultModel/modelLocker';
 16→import { startEditInputWidthAdjuster } from './editInputWidth/index';
 17→import { startExportButton } from './export/index';
 18→import { startAIStudioFolderManager } from './folder/aistudio';
 19→import { startFolderManager } from './folder/index';
 20→import { startFolderSpacingAdjuster } from './folderSpacing/index';
 21→import { isForkFeatureEnabledValue } from './fork/featureFlag';
 22→import { startFork } from './fork/index';
 23→import { startGemsHider } from './gemsHider/index';
 24→import { startInputCollapse } from './inputCollapse/index';
 25→import { initKaTeXConfig } from './katexConfig';
 26→import { startMarkdownPatcher } from './markdownPatcher/index';
 27→import { startMermaid } from './mermaid/index';
 28→import { startPreventAutoScroll } from './preventAutoScroll/index';
 29→import { startPromptManager } from './prompt/index';
 30→import { startQuoteReply } from './quoteReply/index';
 31→import { startRecentsHider } from './recentsHider/index';
 32→import { startSendBehavior } from './sendBehavior/index';
 33→import { startSidebarAutoHide } from './sidebarAutoHide';
 34→import { startSidebarWidthAdjuster } from './sidebarWidth';
 35→import { startTimeline } from './timeline/index';
 36→import { startTitleUpdater } from './titleUpdater';
 37→import { startUserLatex } from './userLatex/index';
 38→import { startRainEffect, startSakuraEffect, startSnowEffect } from './visualEffects';
 39→import { startWatermarkRemover } from './watermarkRemover/index';
 40→
 41→// Suppress Vite's CSS preload errors in the Chrome extension content script context.
 42→// Dynamic imports (e.g., mermaid) trigger Vite's __vitePreload helper which tries to
 43→// create <link> elements with paths like "/assets/foo.css". In a content script, these
 44→// resolve to the web page origin (e.g., https://gemini.google.com/assets/foo.css)
 45→// instead of the extension, causing false "Unable to preload CSS" errors.
 46→// The CSS is already injected via contentStyle.css, so these preloads are unnecessary.
 47→window.addEventListener('vite:preloadError', (event) => {
 48→  event.preventDefault();
 49→});
 50→
 51→/**
 52→ * Staggered initialization to prevent "thundering herd" problem when multiple tabs
 53→ * are restored simultaneously (e.g., after browser restart).
 54→ *
 55→ * Background tabs get a random delay (3-8s) to distribute initialization load.
 56→ * Foreground tabs initialize immediately for good UX.
 57→ *
 58→ * This prevents triggering Google's rate limiting when restoring sessions with
 59→ * many Gemini tabs containing long conversations.
 60→ */
 61→
 62→// Initialization delay constants (in milliseconds)
 63→const HEAVY_FEATURE_INIT_DELAY = 100; // For resource-intensive features (Timeline, Folder)
 64→const LIGHT_FEATURE_INIT_DELAY = 50; // For lightweight features
 65→const BACKGROUND_TAB_MIN_DELAY = 3000; // Minimum delay for background tabs
