332→    return 0;
333→  } else {
334→    // Background tab: add random delay to distribute load across multiple tabs
335→    const randomRange = BACKGROUND_TAB_MAX_DELAY - BACKGROUND_TAB_MIN_DELAY;
336→    const randomDelay = BACKGROUND_TAB_MIN_DELAY + Math.random() * randomRange;
337→    console.log(
