375→    window.addEventListener('unhandledrejection', onUnhandledRejection);
376→    window.addEventListener('error', onWindowError);
377→    const onStorageChanged = (
378→      changes: Record<string, chrome.storage.StorageChange>,
379→      areaName: string,
