404→    const isSupportedSite =
405→      hostname.includes('gemini.google.com') ||
406→      hostname.includes('business.gemini.google') ||
407→      hostname.includes('aistudio.google.com') ||
408→      hostname.includes('aistudio.google.cn');
409→
410→    // Initialize KaTeX configuration early to suppress Unicode warnings
411→    // This must run before any formulas are rendered on the page
412→    if (isSupportedSite) {
