419→    if (!isSupportedSite) {
420→      // For unknown sites, check storage asynchronously
421→      chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] }, (result) => {
422→        const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
423→          ? result.gvPromptCustomWebsites
424→          : [];
425→        const currentHost = hostname.replace(/^www\./, '');
426→
427→        const isCustomSite = customWebsites.some((website: string) => {
428→          const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
429→          return currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
430→        });
431→
432→        if (isCustomSite) {
433→          console.log('[Gemini Voyager] Custom website detected:', hostname);
