  1→/**
  2→ * User Message LaTeX Renderer
  3→ * Renders LaTeX math ($...$ and $$...$$) in user-typed messages.
  4→ *
  5→ * Target DOM structure (Gemini):
  6→ *   span.user-query-bubble-with-background
  7→ *     └─ span.horizontal-container
  8→ *          └─ div.query-text.gds-body-l
  9→ *               ├─ span.cdk-visually-hidden  ("你说" / "You said")
 10→ *               └─ p.query-text-line.ng-star-inserted  ← processed here
 11→ */
 12→import katex from 'katex';
 13→
 14→/** Selector for user message text paragraph elements. */
 15→const USER_MSG_SELECTOR = 'p.query-text-line';
 16→
 17→type Segment = { kind: 'text'; value: string } | { kind: 'math'; value: string; display: boolean };
 18→
 19→/**
 20→ * Check if a character is a digit, indicating a currency context (e.g. $5).
 21→ */
 22→function isDigit(ch: string | undefined): boolean {
 23→  if (!ch) return false;
 24→  return /\d/.test(ch);
 25→}
 26→
 27→/**
 28→ * Split text into plain-text and LaTeX ($$...$$, $...$) segments.
 29→ * Display math ($$) takes priority over inline ($).
 30→ *
 31→ * For inline math ($...$), we require:
 32→ * - The opening $ must NOT be followed by a digit (to avoid matching $5, $3 etc.)
 33→ * - The closing $ must NOT be preceded by a digit that follows a non-math pattern
 34→ * - The content between delimiters must contain at least one non-digit character
 35→ *   (pure numbers like $5$ are likely currency, not math)
 36→ */
 37→export function parseSegments(text: string): Segment[] {
 38→  const out: Segment[] = [];
 39→  let i = 0;
 40→  let textStart = 0;
 41→
 42→  while (i < text.length) {
 43→    if (text[i] !== '$') {
 44→      i++;
 45→      continue;
 46→    }
 47→
 48→    const display = text[i + 1] === '$';
 49→    const openLen = display ? 2 : 1;
 50→
 51→    // For inline math, find the closing delimiter
 52→    let closeIdx: number;
 53→    if (display) {
 54→      closeIdx = text.indexOf('$$', i + openLen);
 55→    } else {
 56→      // For inline math: skip if $ is immediately followed by a digit (likely currency)
 57→      if (isDigit(text[i + 1])) {
 58→        // Skip currency-like $N / $N.NN / $N,NNN patterns without consuming
 59→        // later math openers elsewhere in the string.
 60→        let j = i + 1;
 61→        while (j < text.length && /[\d,.]/.test(text[j])) {
 62→          j++;
 63→        }
 64→        // Handle paired currency token like $5$
 65→        if (text[j] === '$') {
 66→          j++;
 67→        }
 68→        i = j;
 69→        continue;
 70→      }
 71→
 72→      // Find a standalone $ (not part of $$)
 73→      closeIdx = -1;
 74→      let search = i + openLen;
 75→      while (search < text.length) {
 76→        const idx = text.indexOf('$', search);
 77→        if (idx === -1) break;
 78→        // Skip if this $ is part of a $$ sequence
 79→        if (text[idx + 1] === '$' || (idx > 0 && text[idx - 1] === '$')) {
 80→          search = idx + 1;
 81→          continue;
 82→        }
 83→        closeIdx = idx;
 84→        break;
 85→      }
 86→    }
 87→
 88→    if (closeIdx === -1) {
 89→      // No closing delimiter — treat this $ as plain text and move on
 90→      i++;
 91→      continue;
 92→    }
 93→
 94→    const mathValue = text.slice(i + openLen, closeIdx);
 95→
 96→    // For inline math: skip if content is empty or purely numeric (likely currency)
 97→    // Advance past the closing $ to avoid corrupting later parsing
 98→    if (!display && (!mathValue.trim() || /^\d+([.,]\d+)?$/.test(mathValue.trim()))) {
 99→      i = closeIdx + 1;
100→      continue;
101→    }
102→
103→    // Flush accumulated plain text
104→    if (i > textStart) {
105→      out.push({ kind: 'text', value: text.slice(textStart, i) });
106→    }
107→
108→    out.push({ kind: 'math', value: mathValue, display });
109→
110→    i = closeIdx + openLen;
111→    textStart = i;
112→  }
113→
114→  // Remaining plain text
115→  if (textStart < text.length) {
116→    out.push({ kind: 'text', value: text.slice(textStart) });
117→  }
118→
119→  return out;
120→}
121→
122→/**
123→ * Render LaTeX in a single user message paragraph element.
124→ */
125→function processElement(el: HTMLElement): void {
126→  if (el.dataset.userLatexProcessed) return;
127→
128→  const raw = el.textContent ?? '';
129→
130→  // Quick exit: no $ means no LaTeX
131→  if (!raw.includes('$')) {
132→    el.dataset.userLatexProcessed = '1';
133→    return;
134→  }
135→
136→  const segments = parseSegments(raw);
137→  const hasMath = segments.some((s) => s.kind === 'math');
138→
139→  if (!hasMath) {
140→    el.dataset.userLatexProcessed = '1';
141→    return;
142→  }
143→
144→  const frag = document.createDocumentFragment();
145→
146→  for (const seg of segments) {
147→    if (seg.kind === 'text') {
148→      frag.appendChild(document.createTextNode(seg.value));
149→    } else {
150→      const span = document.createElement('span');
151→      span.className = seg.display ? 'gv-user-latex-display' : 'gv-user-latex-inline';
152→      try {
153→        span.innerHTML = katex.renderToString(seg.value, {
154→          displayMode: seg.display,
155→          throwOnError: false,
156→          output: 'html',
157→        });
158→      } catch {
159→        // Fallback: show original delimiters
160→        span.textContent = seg.display ? `$$${seg.value}$$` : `$${seg.value}$`;
161→      }
162→      frag.appendChild(span);
163→    }
164→  }
165→
166→  // Replace element content with rendered output
167→  el.textContent = '';
168→  el.appendChild(frag);
169→  el.dataset.userLatexProcessed = '1';
170→}
171→
172→/** Scan all currently visible user message lines. */
173→function processAll(): void {
174→  document.querySelectorAll<HTMLElement>(USER_MSG_SELECTOR).forEach(processElement);
175→}
176→
177→let observer: MutationObserver | null = null;
178→
179→/**
180→ * Start rendering LaTeX in user messages.
181→ * Processes existing messages immediately and watches for new ones.
182→ */
183→export function startUserLatex(): void {
184→  // Process messages already on the page
185→  processAll();
186→
187→  if (observer) return;
188→
189→  let debounceTimer: ReturnType<typeof setTimeout>;
190→  observer = new MutationObserver(() => {
191→    clearTimeout(debounceTimer);
192→    debounceTimer = setTimeout(processAll, 300);
193→  });
194→
195→  observer.observe(document.body, {
196→    childList: true,
197→    subtree: true,
198→  });
199→}
