/**
 * Check whether a $..$ span contains only currency-like content:
 * pure digits with optional commas/periods (e.g. "5", "3.50", "1,000").
 * Returns false for math that happens to start with a digit (e.g. "2x+1", "10^2").
 */
function isCurrencyContent(content: string): boolean {
  const trimmed = content.trim();
  if (!trimmed) return true; // empty — not valid math either
  return /^[\d,.]+$/.test(trimmed);
}

/**
 * Split text into plain-text and LaTeX ($$...$$, $...$) segments.
 * Display math ($$) takes priority over inline ($).
 *
 * Currency amounts like $5, $3.50, $1,000 are detected by checking whether
 * the content between $ delimiters is purely numeric. Math expressions that
 * start with digits (e.g. $2x+1$, $10^2$) are still rendered.
 */
export function parseSegments(text: string): Segment[] {
  const out: Segment[] = [];
  let i = 0;
  let textStart = 0;

  while (i < text.length) {
    if (text[i] !== '$') {
      i++;
      continue;
    }

    const display = text[i + 1] === '$';
    const openLen = display ? 2 : 1;

    // Find the closing delimiter
    let closeIdx: number;
    if (display) {
      closeIdx = text.indexOf('$$', i + openLen);
    } else {
      // Find a standalone $ (not part of $$)
      closeIdx = -1;
      let search = i + openLen;
      while (search < text.length) {
        const idx = text.indexOf('$', search);
        if (idx === -1) break;
        // Skip if this $ is part of a $$ sequence
        if (text[idx + 1] === '$' || (idx > 0 && text[idx - 1] === '$')) {
          search = idx + 1;
          continue;
        }
        closeIdx = idx;
        break;
      }
    }

    if (closeIdx === -1) {
      // No closing delimiter — treat this $ as plain text and move on
      i++;
      continue;
    }

    const mathValue = text.slice(i + openLen, closeIdx);

    // For inline math: skip if content looks like currency (purely numeric)
    // Advance past the closing $ to avoid corrupting later parsing
    if (!display && isCurrencyContent(mathValue)) {
      i = closeIdx + 1;
      continue;
    }

    // Flush accumulated plain text
    if (i > textStart) {
      out.push({ kind: 'text', value: text.slice(textStart, i) });
    }

    out.push({ kind: 'math', value: mathValue, display });

    i = closeIdx + openLen;
    textStart = i;
  }

  // Remaining plain text
  if (textStart < text.length) {
