  1→/**
  2→ * DOM Content Extractor
  3→ * Extracts rich content from Gemini's DOM structure preserving formatting
  4→ */
  5→
  6→export interface ExtractedContent {
  7→  text: string;
  8→  html: string;
  9→  hasImages: boolean;
 10→  hasFormulas: boolean;
 11→  hasTables: boolean;
 12→  hasCode: boolean;
 13→}
 14→
 15→export interface ExtractedTurn {
 16→  user: ExtractedContent;
 17→  assistant: ExtractedContent;
 18→  starred: boolean;
 19→}
 20→
 21→/**
 22→ * Extracts structured content from Gemini's DOM
 23→ * Preserves formatting including LaTeX formulas, code blocks, tables, etc.
 24→ */
 25→
 26→/**
 27→ * querySelector variant that skips elements nested inside model-thoughts / thoughts-container.
 28→ * When the user expands Gemini's "thinking" section, a second `message-content` element
 29→ * appears *before* the real response in DOM order.  A plain `querySelector` would match
 30→ * the thinking panel first, causing exports to grab the wrong content.
 31→ */
 32→function queryOutsideThoughts<T extends Element = Element>(
 33→  root: Element,
 34→  selector: string,
 35→): T | null {
 36→  const candidates = root.querySelectorAll<T>(selector);
 37→  for (const el of Array.from(candidates)) {
 38→    if (!el.closest('model-thoughts, .thoughts-container, .thoughts-content')) {
 39→      return el;
 40→    }
 41→  }
 42→  return null;
 43→}
 44→export class DOMContentExtractor {
 45→  private static DEBUG = false;
 46→  /**
 47→   * Extract user query content
 48→   */
 49→  static extractUserContent(element: HTMLElement): ExtractedContent {
 50→    const result: ExtractedContent = {
 51→      text: '',
 52→      html: '',
 53→      hasImages: false,
 54→      hasFormulas: false,
 55→      hasTables: false,
 56→      hasCode: false,
 57→    };
 58→
 59→    // Check for images
 60→    const images = element.querySelectorAll('user-query-file-preview img, .preview-image');
 61→    result.hasImages = images.length > 0;
 62→
 63→    // Extract text from query-text-line paragraphs
 64→    const textLines = element.querySelectorAll('.query-text-line');
 65→    const textParts: string[] = [];
 66→    textLines.forEach((line) => {
 67→      const text = this.normalizeText(line.textContent || '');
 68→      if (text) textParts.push(text);
 69→    });
 70→    result.text = textParts.join('\n');
 71→
 72→    // Build HTML representation
 73→    const htmlParts: string[] = [];
 74→
 75→    // Add image markdown
 76→    const imageMarkdown: string[] = [];
 77→    images.forEach((img, index) => {
 78→      const src = (img as HTMLImageElement).src;
 79→      const alt = (img as HTMLImageElement).alt || `Uploaded image ${index + 1}`;
 80→      htmlParts.push(`<img src="${src}" alt="${alt}" />`);
 81→      imageMarkdown.push(`![${alt}](${src})`);
 82→    });
 83→
 84→    // Combine image markdown and text
 85→    const allTextParts: string[] = [];
 86→    if (imageMarkdown.length > 0) {
 87→      allTextParts.push(imageMarkdown.join('\n\n'));
 88→    }
 89→    if (textParts.length > 0) {
 90→      allTextParts.push(textParts.join('\n'));
 91→    }
 92→    result.text = allTextParts.join('\n\n');
 93→
 94→    // Add text paragraphs to HTML
 95→    textParts.forEach((text) => {
 96→      htmlParts.push(`<p>${this.escapeHtml(text)}</p>`);
 97→    });
 98→
 99→    result.html = htmlParts.join('\n');
100→
101→    return result;
102→  }
103→
104→  /**
105→   * Extract assistant response content with rich formatting
106→   */
107→  static extractAssistantContent(element: HTMLElement): ExtractedContent {
108→    if (this.DEBUG)
109→      console.log('[DOMContentExtractor] extractAssistantContent called, element:', element);
110→
111→    const result: ExtractedContent = {
112→      text: '',
113→      html: '',
114→      hasImages: false,
115→      hasFormulas: false,
116→      hasTables: false,
117→      hasCode: false,
118→    };
119→
120→    // Find message-content first (contains main text and formulas)
121→    // Use queryOutsideThoughts to avoid matching the message-content inside
122→    // the expanded thinking/reasoning panel.
123→    let messageContent = queryOutsideThoughts(element, 'message-content');
124→
125→    if (!messageContent) {
126→      // Try markdown container
127→      messageContent = queryOutsideThoughts(
128→        element,
129→        '.markdown-main-panel, ' + '.markdown, ' + '.model-response-text',
130→      );
131→    }
132→
133→    // If still not found, check if element itself is a valid container
134→    if (!messageContent) {
135→      if (
136→        element.classList.contains('markdown') ||
137→        element.tagName.toLowerCase() === 'message-content'
138→      ) {
139→        messageContent = element;
140→      }
141→    }
142→
143→    if (!messageContent) {
144→      // Last resort: use element directly
145→      console.warn('[DOMContentExtractor] Response container not found, using element directly');
146→      messageContent = element;
147→    }
148→
149→    if (this.DEBUG)
150→      console.log(
151→        '[DOMContentExtractor] Using container:',
152→        messageContent.tagName,
153→        messageContent.className,
154→      );
155→
156→    // Don't clone! Angular custom elements may lose content when cloned
157→    // Instead, skip model-thoughts during processNodes
158→    const htmlParts: string[] = [];
159→    const textParts: string[] = [];
160→
161→    // STRATEGY CHANGE: Instead of recursing through DOM (which misses Angular-rendered elements),
162→    // process the .markdown div directly and then search for response-elements
163→    const markdownDiv = messageContent.querySelector('.markdown, .markdown-main-panel');
164→
165→    if (this.DEBUG) {
166→      console.log('[DOMContentExtractor] messageContent tagName:', messageContent.tagName);
167→      console.log('[DOMContentExtractor] messageContent className:', messageContent.className);
168→      console.log('[DOMContentExtractor] markdownDiv found?', !!markdownDiv);
169→    }
170→
171→    if (markdownDiv) {
172→      if (this.DEBUG) {
173→        console.log('[DOMContentExtractor] markdownDiv tagName:', markdownDiv.tagName);
174→        console.log('[DOMContentExtractor] markdownDiv className:', markdownDiv.className);
175→        console.log(
176→          '[DOMContentExtractor] markdownDiv innerHTML preview:',
177→          (markdownDiv as HTMLElement).innerHTML.substring(0, 300),
178→        );
179→      }
180→
181→      // First, process all direct children of markdown that are NOT response-element
182→      this.processNodes(markdownDiv, htmlParts, textParts, result);
183→
184→      // Note: response-element contents are processed by processNodes recursion above
185→    } else {
186→      // Fallback to old method
187→      if (this.DEBUG) console.log('[DOMContentExtractor] No markdown div found, using fallback');
188→      this.processNodes(messageContent, htmlParts, textParts, result);
189→    }
190→
191→    // Additionally, look for code blocks and tables at the element level
192→    // These might be siblings to message-content in response-element containers
193→    // IMPORTANT: Angular may use Shadow DOM, so we need to search both light DOM and shadow DOM
194→    if (this.DEBUG) {
195→      console.log(
196→        '[DOMContentExtractor] Searching for code blocks in:',
197→        element.tagName,
198→        element.className,
199→      );
200→      console.log(
201→        '[DOMContentExtractor] Element HTML preview:',
202→        element.outerHTML.substring(0, 200),
203→      );
204→    }
205→
206→    // Helper function to search in both light DOM and shadow DOM
207→    const searchAll = (root: Element, selector: string): Element[] => {
208→      const results: Element[] = [];
209→
210→      // Search in light DOM
211→      results.push(...Array.from(root.querySelectorAll(selector)));
212→
213→      // Search in shadow DOM recursively
214→      const searchShadow = (el: Element) => {
215→        const shadowRoot = el.shadowRoot;
216→        if (shadowRoot) {
217→          console.log(`[DOMContentExtractor] Searching in Shadow DOM of`, el.tagName);
218→          results.push(...Array.from(shadowRoot.querySelectorAll(selector)));
219→        }
220→
221→        // Recursively check children for shadow roots
222→        Array.from(el.children).forEach(searchShadow);
223→      };
224→
225→      searchShadow(root);
226→      return results;
227→    };
228→
229→    // Also search for raw code elements regardless of presence of code-block
230→    const altCodeBlocks = searchAll(messageContent, 'pre > code, [data-test-id="code-content"]');
231→    if (this.DEBUG)
232→      console.log(
233→        '[DOMContentExtractor] Found',
234→        altCodeBlocks.length,
235→        'raw code elements with alternative selector',
236→      );
237→    altCodeBlocks.forEach((codeEl, idx) => {
238→      // Avoid duplicates if already processed
239→      if ((codeEl as Element & { processedByGV?: boolean }).processedByGV) return;
240→      // Skip if inside a code-block (already handled by processNodes)
241→      if (codeEl.closest && codeEl.closest('code-block')) return;
242→      if (this.DEBUG)
243→        console.log(
244→          `[DOMContentExtractor] Processing raw code element ${idx + 1}/${altCodeBlocks.length}`,
245→        );
246→      const extracted = this.extractCodeFromCodeElement(codeEl as HTMLElement);
247→      if (extracted.text) {
248→        (codeEl as Element & { processedByGV?: boolean }).processedByGV = true;
249→        result.hasCode = true;
250→        htmlParts.push(extracted.html);
251→        textParts.push(`\n${extracted.text}\n`);
252→      }
253→    });
254→    // Note: tables and code-blocks were already processed via processNodes()
255→
256→    result.html = htmlParts.join('\n');
257→    // Clean up multiple newlines but preserve intentional spacing
258→    let combinedText = textParts
259→      .join('')
260→      .replace(/\n{3,}/g, '\n\n') // Max 2 consecutive newlines
261→      .trim();
262→    // Last-chance fallback: if no structured text captured, use plain innerText
263→    if (!combinedText) {
264→      const fallbackContainer =
265→        (messageContent as HTMLElement) ||
266→        queryOutsideThoughts<HTMLElement>(element, 'message-content') ||
267→        (element as HTMLElement);
268→      try {
269→        const plain =
270→          (fallbackContainer as HTMLElement).innerText || fallbackContainer.textContent || '';
271→        combinedText = this.normalizeText(plain);
272→      } catch {
273→        /* ignore */
274→      }
275→    }
276→    result.text = combinedText;
277→
278→    return result;
279→  }
280→
281→  /**
282→   * Process DOM nodes recursively
283→   */
284→  private static processNodes(
285→    container: Element,
286→    htmlParts: string[],
287→    textParts: string[],
288→    flags: Pick<ExtractedContent, 'hasImages' | 'hasFormulas' | 'hasTables' | 'hasCode'>,
289→  ): void {
290→    const children = Array.from(container.children);
291→    if (this.DEBUG)
292→      console.log(
293→        `[DOMContentExtractor] processNodes: ${children.length} children in`,
294→        container.tagName,
295→        container.className,
296→      );
297→
298→    // Check for Shadow DOM
299→    const shadowRoot = container.shadowRoot;
300→    if (shadowRoot) {
301→      if (this.DEBUG)
302→        console.log('[DOMContentExtractor] Found Shadow DOM! Processing shadow children');
303→      this.processNodes(shadowRoot as unknown as Element, htmlParts, textParts, flags);
304→    }
305→
306→    for (const child of children) {
307→      const tagName = child.tagName.toLowerCase();
308→      if (this.DEBUG)
309→        console.log('[DOMContentExtractor] Processing child:', tagName, child.className);
310→
311→      // Skip certain elements
312→      if (this.shouldSkipElement(child)) {
313→        if (this.DEBUG) console.log('[DOMContentExtractor] Skipping element:', tagName);
314→        continue;
315→      }
316→
317→      // Images
318→      if (tagName === 'img') {
319→        const img = child as HTMLImageElement;
320→        const src = img.getAttribute('src') || img.src || '';
321→        if (src && src !== 'about:blank') {
322→          flags.hasImages = true;
323→          const altRaw = img.getAttribute('alt') || '';
324→          const alt = altRaw.trim() || 'Image';
325→          htmlParts.push(
326→            `<img src="${this.escapeHtmlAttribute(src)}" alt="${this.escapeHtmlAttribute(alt)}" />`,
327→          );
328→          const mdAlt = alt.replace(/\]/g, '\\]');
329→          textParts.push(`\n![${mdAlt}](${src})\n`);
330→        }
331→        continue;
332→      }
333→
334→      // Math block (display formula) - check both class and data-math attribute
335→      if (child.classList.contains('math-block') || child.hasAttribute('data-math')) {
336→        const latex = child.getAttribute('data-math') || '';
337→        if (latex) {
338→          if (this.DEBUG) console.log('[DOMContentExtractor] Found math-block, latex:', latex);
339→          flags.hasFormulas = true;
340→          // For HTML output: preserve the rendered formula HTML for PDF export
341→          // Clone the element to preserve its rendered content
342→          const clonedFormula = (child as HTMLElement).cloneNode(true) as HTMLElement;
343→          // Ensure data-math attribute is preserved for potential re-rendering
344→          if (!clonedFormula.hasAttribute('data-math')) {
345→            clonedFormula.setAttribute('data-math', latex);
346→          }
347→          htmlParts.push(clonedFormula.outerHTML);
348→          // For text output: use Markdown format
349→          textParts.push(`\n$$\n${latex}\n$$\n`);
350→          continue;
351→        }
352→      }
353→
354→      // Code block (check for nested code-block first)
355→      const codeBlock = child.querySelector('code-block');
356→      if (tagName === 'code-block' || child.classList.contains('code-block') || codeBlock) {
357→        if (this.DEBUG) console.log('[DOMContentExtractor] Found code block!');
358→        const elementToExtract = (codeBlock || child) as HTMLElement;
359→        const codeContent = this.extractCodeBlock(elementToExtract);
360→        if (this.DEBUG) console.log('[DOMContentExtractor] Code content:', codeContent.text);
361→        if (codeContent.text) {
362→          flags.hasCode = true;
363→          htmlParts.push(codeContent.html);
364→          textParts.push(`\n${codeContent.text}\n`);
365→        }
366→        continue;
367→      }
368→
369→      // Table block (check for nested table-block first)
370→      const tableBlock = child.querySelector('table-block');
371→      if (tagName === 'table-block' || tableBlock || child.querySelector('table')) {
372→        if (this.DEBUG) console.log('[DOMContentExtractor] Found table block!');
373→        const elementToExtract = (tableBlock || child) as HTMLElement;
374→        const tableContent = this.extractTable(elementToExtract);
375→        if (this.DEBUG) console.log('[DOMContentExtractor] Table content:', tableContent.text);
376→        if (tableContent.text) {
377→          // Only add if table was successfully extracted
378→          flags.hasTables = true;
379→          htmlParts.push(tableContent.html);
380→          textParts.push(`\n${tableContent.text}\n`);
381→        }
382→        continue;
383→      }
384→
385→      // Search result images (web images found by Gemini)
386→      // Structure: <div.attachment-container.search-images> > <response-element> >
387→      //   <single-image> > <div.image-container[data-full-size-image-uri]> > ... > <img>
388→      {
389→        const searchImageContainers = child.querySelectorAll(
390→          '.attachment-container.search-images .image-container[data-full-size-image-uri]',
391→        );
392→        if (searchImageContainers.length > 0) {
393→          for (const container of Array.from(searchImageContainers)) {
394→            const fullSizeUri = container.getAttribute('data-full-size-image-uri') || '';
395→            const imgEl = container.querySelector('img.image') as HTMLImageElement | null;
396→            if (!imgEl) continue;
397→            // Use the Google-cached thumbnail (gstatic.com) as the downloadable src.
398→            // The full-size URI points to arbitrary third-party domains that are blocked
399→            // by both CORS and Gemini's CSP, so it's only usable as an attribution link.
400→            const src = imgEl.src || '';
401→            if (!src || src === 'about:blank') continue;
402→            const alt = imgEl.alt || 'Search result image';
403→            const sourceLink = container.querySelector('a.source') as HTMLAnchorElement | null;
404→            const sourceUrl = sourceLink?.href || '';
405→            const sourceLabel =
406→              container.querySelector('.source .label')?.textContent?.trim() || '';
407→
408→            flags.hasImages = true;
409→            htmlParts.push(
410→              `<img src="${this.escapeHtmlAttribute(src)}" alt="${this.escapeHtmlAttribute(alt)}" />`,
411→            );
412→            const mdAlt = alt.replace(/\]/g, '\\]');
413→            // Link to the full-size image or source when available
414→            const linkUrl = fullSizeUri || sourceUrl;
415→            const linkLabel = sourceLabel || (sourceUrl ? sourceUrl : '');
416→            if (linkUrl) {
417→              textParts.push(
418→                `\n![${mdAlt}](${src})\n*Source: [${linkLabel || linkUrl}](${linkUrl})*\n`,
419→              );
420→            } else {
421→              textParts.push(`\n![${mdAlt}](${src})\n`);
422→            }
423→          }
424→          if (this.DEBUG)
425→            console.log(
426→              '[DOMContentExtractor] Extracted',
427→              searchImageContainers.length,
428→              'search result images',
429→            );
430→          continue;
431→        }
432→      }
433→
434→      // Generated images (model-generated images in assistant responses)
435→      // These are typically wrapped in: <p> > <div.attachment-container.generated-images> >
436→      //   <response-element> > <generated-image> > <single-image> > ... > <img>
437→      // Also handle standalone generated-image / single-image custom elements
438→      {
439→        const generatedImgs = child.querySelectorAll(
440→          'generated-image img, single-image img, .attachment-container.generated-images img',
441→        );
442→        if (generatedImgs.length > 0) {
443→          for (const img of Array.from(generatedImgs)) {
444→            const imgEl = img as HTMLImageElement;
445→            const src = imgEl.src || imgEl.getAttribute('src') || '';
446→            if (!src || src === 'about:blank') continue;
447→            const alt = imgEl.alt || 'Generated image';
448→            flags.hasImages = true;
449→            htmlParts.push(
450→              `<img src="${this.escapeHtmlAttribute(src)}" alt="${this.escapeHtmlAttribute(alt)}" />`,
451→            );
452→            const mdAlt = alt.replace(/\]/g, '\\]');
453→            textParts.push(`\n![${mdAlt}](${src})\n`);
454→          }
455→          if (this.DEBUG)
456→            console.log(
457→              '[DOMContentExtractor] Extracted',
458→              generatedImgs.length,
459→              'generated images',
460→            );
461→          continue;
462→        }
463→      }
464→
465→      // Horizontal rule
466→      if (tagName === 'hr') {
467→        htmlParts.push('<hr>');
468→        textParts.push('\n---\n');
469→        continue;
470→      }
471→
472→      // Paragraph with possible inline formulas
473→      if (tagName === 'p') {
474→        const processed = this.processInlineContent(child as HTMLElement);
475→        if (processed.hasFormulas) flags.hasFormulas = true;
476→        htmlParts.push(`<p>${processed.html}</p>`);
477→        textParts.push(`${processed.text}\n`);
478→        continue;
479→      }
480→
481→      // Headings
482→      if (/^h[1-6]$/.test(tagName)) {
483→        const text = this.extractTextWithInlineFormulas(child as HTMLElement);
484→        const level = tagName[1];
485→        htmlParts.push(`<h${level}>${text.html}</h${level}>`);
486→        textParts.push(`\n${'#'.repeat(parseInt(level))} ${text.text}\n`);
487→        continue;
488→      }
489→
490→      // Lists
491→      if (tagName === 'ul' || tagName === 'ol') {
492→        const listContent = this.extractList(child as HTMLElement);
493→        htmlParts.push(listContent.html);
494→        textParts.push(`\n${listContent.text}\n`);
495→        continue;
496→      }
497→
498→      // Generic containers - recurse into children
499→      if (
500→        tagName === 'response-element' ||
501→        tagName === 'div' ||
502→        tagName === 'section' ||
503→        tagName === 'article' ||
504→        tagName === 'generated-image' ||
505→        tagName === 'single-image' ||
506→        child.classList.contains('horizontal-scroll-wrapper') ||
507→        child.classList.contains('table-block-component')
508→      ) {
509→        if (this.DEBUG)
510→          console.log('[DOMContentExtractor] Recursing into container:', tagName, child.className);
511→        // Recursively process children instead of extracting text directly
512→        this.processNodes(child, htmlParts, textParts, flags);
513→        continue;
514→      }
515→
516→      // Default: extract text content for unknown inline elements
517→      const text = this.normalizeText(child.textContent || '');
518→      if (text) {
519→        // Only add text if it's not already processed by parent
520→        htmlParts.push(`<span>${this.escapeHtml(text)}</span>`);
521→        textParts.push(text);
522→      }
523→    }
524→  }
