572→  /**
573→   * Process inline content (text with inline formulas)
574→   */
575→  private static processInlineContent(element: HTMLElement): {
576→    html: string;
577→    text: string;
578→    hasFormulas: boolean;
579→  } {
580→    let hasFormulas = false;
581→    const htmlParts: string[] = [];
582→    const textParts: string[] = [];
583→
584→    // Process all child nodes including text nodes
585→    const processNode = (node: Node): void => {
586→      if (node.nodeType === Node.TEXT_NODE) {
587→        const text = node.textContent || '';
588→        if (text.trim()) {
589→          htmlParts.push(this.escapeHtml(text));
590→          textParts.push(text);
591→        }
592→      } else if (node.nodeType === Node.ELEMENT_NODE) {
593→        const el = node as Element;
594→
595→        if (this.shouldSkipElement(el)) {
596→          return;
597→        }
598→
599→        // Inline formula - check both class and data-math attribute
600→        if (el.classList.contains('math-inline') || el.hasAttribute('data-math')) {
601→          const latex = el.getAttribute('data-math') || '';
602→          if (latex) {
603→            hasFormulas = true;
604→            // For HTML output: preserve the rendered formula HTML for PDF export
605→            const clonedFormula = (el as HTMLElement).cloneNode(true) as HTMLElement;
606→            // Ensure data-math attribute is preserved
607→            if (!clonedFormula.hasAttribute('data-math')) {
608→              clonedFormula.setAttribute('data-math', latex);
609→            }
610→            htmlParts.push(clonedFormula.outerHTML);
611→            // For text output: use Markdown format
612→            textParts.push(`$${latex}$`);
613→            return;
614→          }
615→        }
616→
617→        // Emphasis
618→        if (el.tagName === 'I' || el.tagName === 'EM') {
619→          const text = this.normalizeText(el.textContent || '');
620→          htmlParts.push(`<em>${this.escapeHtml(text)}</em>`);
621→          textParts.push(`*${text}*`);
622→          return;
623→        }
624→
625→        // Strong
626→        if (el.tagName === 'B' || el.tagName === 'STRONG') {
627→          const text = this.normalizeText(el.textContent || '');
628→          htmlParts.push(`<strong>${this.escapeHtml(text)}</strong>`);
629→          textParts.push(`**${text}**`);
630→          return;
631→        }
632→
633→        // Code
634→        if (el.tagName === 'CODE' && !el.closest('pre')) {
635→          const text = this.normalizeText(el.textContent || '');
636→          htmlParts.push(`<code>${this.escapeHtml(text)}</code>`);
637→          textParts.push(`\`${text}\``);
638→          return;
639→        }
640→
641→        // Inline images
642→        if (el.tagName === 'IMG') {
643→          const imgEl = el as HTMLImageElement;
644→          const src = imgEl.src || imgEl.getAttribute('src') || '';
645→          if (src && src !== 'about:blank') {
646→            const alt = imgEl.alt || 'Image';
647→            htmlParts.push(
648→              `<img src="${this.escapeHtmlAttribute(src)}" alt="${this.escapeHtmlAttribute(alt)}" />`,
649→            );
650→            const mdAlt = alt.replace(/\]/g, '\\]');
651→            textParts.push(`![${mdAlt}](${src})`);
652→          }
653→          return;
654→        }
655→
656→        // Recurse for other elements
657→        Array.from(el.childNodes).forEach(processNode);
658→      }
659→    };
660→
661→    Array.from(element.childNodes).forEach(processNode);
662→
663→    return {
664→      html: htmlParts.join(''),
665→      text: textParts.join(''),
666→      hasFormulas,
667→    };
668→  }
