728→  /**
729→   * Extract table content
730→   */
731→  private static extractTable(element: HTMLElement): { html: string; text: string } {
732→    // Accept either a container that holds a <table>, or a <table> element itself
733→    let table: HTMLTableElement | null = null;
734→    if (element.tagName && element.tagName.toLowerCase() === 'table') {
735→      table = element as HTMLTableElement;
736→    } else {
737→      table = element.querySelector('table') as HTMLTableElement | null;
738→    }
739→    if (!table) {
740→      return { html: '', text: '' };
741→    }
742→
743→    // Extract HTML (clean version)
744→    const cleanTable = table.cloneNode(true) as HTMLElement;
745→    this.stripExportArtifacts(cleanTable);
746→
747→    // Convert to Markdown
748→    const rows: string[][] = [];
749→    const headerCells = Array.from(table.querySelectorAll('thead tr td, thead tr th'));
750→    if (headerCells.length > 0) {
751→      rows.push(headerCells.map((cell) => this.normalizeText(cell.textContent || '')));
752→    }
753→
754→    const bodyRows = table.querySelectorAll('tbody tr');
755→    bodyRows.forEach((row) => {
756→      const cells = Array.from(row.querySelectorAll('td, th'));
757→      rows.push(cells.map((cell) => this.normalizeText(cell.textContent || '')));
758→    });
759→
760→    // Build Markdown table
761→    const markdownLines: string[] = [];
762→    if (rows.length > 0) {
763→      // Header
764→      markdownLines.push('| ' + rows[0].join(' | ') + ' |');
765→      markdownLines.push('| ' + rows[0].map(() => '---').join(' | ') + ' |');
766→      // Body
767→      for (let i = 1; i < rows.length; i++) {
768→        markdownLines.push('| ' + rows[i].join(' | ') + ' |');
769→      }
770→    } else {
771→      // Fallback: treat first tbody row as header if no thead present
772→      const firstBodyRow = table.querySelector('tbody tr');
773→      if (firstBodyRow) {
774→        const header = Array.from(firstBodyRow.querySelectorAll('td, th')).map((cell) =>
775→          this.normalizeText(cell.textContent || ''),
776→        );
777→        if (header.length > 0) {
778→          markdownLines.push('| ' + header.join(' | ') + ' |');
779→          markdownLines.push('| ' + header.map(() => '---').join(' | ') + ' |');
780→          const rest = Array.from(table.querySelectorAll('tbody tr')).slice(1);
781→          rest.forEach((row) => {
782→            const cells = Array.from(row.querySelectorAll('td, th')).map((cell) =>
783→              this.normalizeText(cell.textContent || ''),
784→            );
785→            markdownLines.push('| ' + cells.join(' | ') + ' |');
786→          });
787→        }
788→      }
789→    }
790→
791→    return {
792→      html: cleanTable.outerHTML,
793→      text: markdownLines.join('\n'),
794→    };
795→  }
