797→  /**
798→   * Extract list content with support for nested lists
799→   */
800→  private static extractList(
801→    element: HTMLElement,
802→    depth: number = 0,
803→  ): { html: string; text: string } {
804→    const isOrdered = element.tagName === 'OL';
805→    const items = Array.from(element.querySelectorAll(':scope > li'));
806→    const indent = '  '.repeat(depth); // 2 spaces per level
807→
808→    const textLines: string[] = [];
809→    items.forEach((item, index) => {
810→      // Create a temporary container with only direct children (excluding nested lists)
811→      const tempContainer = document.createElement('div');
812→      const childNodes = Array.from(item.childNodes);
813→
814→      childNodes.forEach((node) => {
815→        if (node.nodeType === Node.TEXT_NODE) {
816→          tempContainer.appendChild(node.cloneNode(true));
817→        } else if (node.nodeType === Node.ELEMENT_NODE) {
818→          const el = node as Element;
819→          // Skip nested lists, we'll process them separately
820→          if (el.tagName !== 'UL' && el.tagName !== 'OL') {
821→            tempContainer.appendChild(el.cloneNode(true));
822→          }
823→        }
824→      });
825→
826→      // Process inline content (handles formulas, emphasis, etc.)
827→      const processed = this.processInlineContent(tempContainer);
828→      const itemText = processed.text || this.normalizeText(tempContainer.textContent || '');
829→
830→      const prefix = isOrdered ? `${index + 1}. ` : '- ';
831→      textLines.push(indent + prefix + itemText);
832→
833→      // Process nested lists
834→      const nestedLists = item.querySelectorAll(':scope > ul, :scope > ol');
835→      nestedLists.forEach((nestedList) => {
836→        const nestedResult = this.extractList(nestedList as HTMLElement, depth + 1);
837→        if (nestedResult.text) {
838→          textLines.push(nestedResult.text);
839→        }
840→      });
841→    });
842→
843→    const cleanList = element.cloneNode(true) as HTMLElement;
844→    this.stripExportArtifacts(cleanList);
845→
846→    return {
847→      html: cleanList.outerHTML,
848→      text: textLines.join('\n'),
849→    };
850→  }
